#include <bits/stdc++.h>
using namespace std;

int n, m, k;
bool a[105][105];
int s[105][105];

int main() {
    cin >> n >> m >> k;
    for (int i = 1; i <= n; i++) {
        getchar();
        for (int j = 1; j <= m; j++) {
            int t = getchar() - '0';
            a[i][j] = t;
            int s1 = s[i][j - 1];
            int s2 = s[i - 1][j];
            int s3 = s[i - 1][j - 1];
            s[i][j] = s1 + s2 - s3 + a[i][j];
        }
    }
    int blocks = 10005;
    for (int y1 = 1; y1 <= n; y1++) {
    for (int x1 = 1; x1 <= m; x1++) {
        for (int y2 = y1; y2 <= n; y2++) {
        for (int x2 = x1; x2 <= m; x2++) {
            int sum1 = s[y2][x2];
            int sum2 = s[y1 - 1][x2];
            int sum3 = s[y2][x1 - 1];
            int sum4 = s[y1 - 1][x1 - 1];
            if (sum1 - sum2 - sum3 + sum4 >= k) {
                blocks = min(blocks, (x2 - x1 + 1) * (y2 - y1 + 1));
                break;
            }
            // cout << sum1 - sum2 - sum3 + sum4 << ' ';
        }
        // cout << endl;
        }
        // cout << endl;
    }
    }
    cout << (blocks == 10005 ? 0 : blocks);
